    const result = cmdUpgrade({
      root: tmpDir,
      projectName: 'demo-project',
      goalSummary: 'Build a durable project memory workflow.',
      locale: 'auto',
      date: '2025-06-15',
      time: '14:30',
      format: 'json',
    })

    expect(result).toBe(0)
